import React from 'react';
import './footer.css';

const Footer = () => {
  return (
    <footer id="footer">
      <p>
        Contact Christian Caron <br />
        26 rue des templiers
        <br /> 75000 Paris
        <br />
        Tel: 06-79-24-32-25 <br />
        Mail: requindudev@gmail.com
      </p>
      <p>
        Réalisé par Christian Caron
        <br /> © copyright 2023
      </p>
    </footer>
  );
};

export default Footer;
